const OVERVIEW_VIEWBOX = "0 0 730 600";

const AnimatedCounter = ({ value, suffix = '' }: { value: number; suffix?: string }) => {
  const [displayText, setDisplayText] = useState("0");
  const count = useRef(0);

  useEffect(() => {
    const obj = { val: 0 };
    gsap.to(obj, {
      val: value,
      duration: 1.5,
      ease: "power2.out",
      onUpdate: () => setDisplayText(Math.round(obj.val).toLocaleString())
    });
  }, [value]);

  return <span>{displayText}{suffix}</span>;
};

type Stage = 'OVERVIEW' | 'ZOOMING' | 'REGION_ACTIVE' | 'ZOOMING_OUT';

export default function RegionalPresence() {
  const { language, t, isRTL } = useLanguage();
  const { theme } = useTheme();
  const sectionRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // High-precision stage calculation
  const [activeStage, setActiveStage] = useState<Stage>('OVERVIEW');
  const [activeHubIndex, setActiveHubIndex] = useState(0);

  // viewBox Spring Interpolation
  const vbX = useSpring(0, { stiffness: 40, damping: 15 });
  const vbY = useSpring(0, { stiffness: 40, damping: 15 });
  const vbW = useSpring(730, { stiffness: 40, damping: 15 });
  const vbH = useSpring(600, { stiffness: 40, damping: 15 });

  useEffect(() => {
    const mm = gsap.matchMedia();

    mm.add("(min-width: 1025px)", () => {
      ScrollTrigger.create({
        trigger: sectionRef.current,
        start: 'top top',
        end: `+=${REGIONS_DATA.length * 300}%`,
        pin: true,
        scrub: 1.5,
        anticipatePin: 1,
        onUpdate: (self) => {
          const totalStages = REGIONS_DATA.length;
          const progress = self.progress;
          const hubProgressRaw = progress * totalStages;
          const hubIdx = Math.min(Math.floor(hubProgressRaw), totalStages - 1);
          const localProgress = hubProgressRaw % 1;

          const hub = REGIONS_DATA[hubIdx];
          const [zX, zY, zW, zH] = hub.zoomViewBox.split(' ').map(Number);
          const [oX, oY, oW, oH] = OVERVIEW_VIEWBOX.split(' ').map(Number);

          setActiveHubIndex(hubIdx);

          if (localProgress < 0.15) {
            setActiveStage('OVERVIEW');
            vbX.set(oX); vbY.set(oY); vbW.set(oW); vbH.set(oH);
          } else if (localProgress < 0.45) {
            setActiveStage('ZOOMING');
            vbX.set(zX); vbY.set(zY); vbW.set(zW); vbH.set(zH);
          } else if (localProgress < 0.85) {
            setActiveStage('REGION_ACTIVE');
            vbX.set(zX); vbY.set(zY); vbW.set(zW); vbH.set(zH);
          } else {
            setActiveStage('ZOOMING_OUT');
            vbX.set(oX); vbY.set(oY); vbW.set(oW); vbH.set(oH);
          }
        }
      });
    });

    mm.add("(max-width: 1024px)", () => {
      // Simplified behavior for mobile - no pinning, simple reveal
      ScrollTrigger.create({
        trigger: sectionRef.current,
        start: 'top 80%',
        onEnter: () => setActiveStage('REGION_ACTIVE')
      });
    });

    ScrollTrigger.refresh();
    
    return () => mm.revert();
  }, [vbX, vbY, vbW, vbH, language]);

  const activeHub = REGIONS_DATA[activeHubIndex];
  const isImmersive = activeStage === 'REGION_ACTIVE' || activeStage === 'ZOOMING';

  return (
    <section ref={sectionRef} className={styles.section} id="regional-presence">
      {/* Immersive Section Header */}
      <motion.div 
        className={styles.sectionHeader}
        animate={{ 
          opacity: activeStage === 'OVERVIEW' ? 1 : 0.3,
          y: activeStage === 'OVERVIEW' ? 0 : -20 
        }}
      >
        <h2 className={styles.sectionMainTitle}>
          {t('footprint_title')}
        </h2>
      </motion.div>

      {/* Cinematic Background Layer */}
      <div className={styles.immersiveBgContainer}>
        <AnimatePresence mode="wait">
          {activeStage === 'REGION_ACTIVE' && (
            <motion.div 
              key={activeHub.id}
              initial={{ opacity: 0, scale: 1.1 }}
              animate={{ opacity: 0.6, scale: 1 }}
              exit={{ opacity: 0, scale: 1.05 }}
              transition={{ duration: 1.2, ease: "easeOut" }}
              className={styles.bgImageLayer}
              // Removed placeholder.jpg to fix 404. Relying on the inner <img> for dynamic content.
            >
              {/* Fallback for generated images located in artifacts path during dev */}
              <img 
                src={activeHub.bgImage.startsWith('/') ? activeHub.bgImage : `/assets/images/${activeHub.id}.jpg`} 
                alt={activeHub.nameEn}
                style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: 1 }}
                onError={(e) => {
                    // This handles mapping generated image relative paths to public assets
                    (e.target as HTMLImageElement).src = `https://picsum.photos/seed/${activeHub.id}/1920/1080?grayscale`;
                }}
              />
              <div className={styles.imageOverlay} />
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <div className={styles.pinnedContainer}>
        {/* Map Area */}
        <div className={styles.mapWrapper}>
          <motion.svg 
            // Use local motion values to build the viewBox string string
            viewBox={useTransform(
              [vbX, vbY, vbW, vbH],
              ([x, y, w, h]) => `${x} ${y} ${w} ${h}`
            )}
            className={styles.mapSvg}
            preserveAspectRatio="xMidYMid meet"
          >
            <g className={styles.baseMap}>
              {REGIONS_DATA.map(hub => (
                <path 
                  key={`bg-${hub.id}`} 
                  d={SVG_PATHS[hub.unifiedPath]} 
                  className={styles.regionPath} 
                />
              ))}
            </g>

            {REGIONS_DATA.map((hub, idx) => {
              const isCurrent = idx === activeHubIndex;
              return (
                <g key={hub.id}>
                   <motion.path 
                      d={SVG_PATHS[hub.unifiedPath]} 
                      className={styles.hubFill}
                      animate={{ 
                        fill: isCurrent && activeStage !== 'OVERVIEW'
                            ? (theme === 'dark' ? 'rgba(203, 161, 82, 0.25)' : 'rgba(203, 161, 82, 0.15)') 
                            : 'rgba(26, 115, 232, 0.03)',
                        stroke: isCurrent ? 'rgba(203, 161, 82, 0.4)' : 'rgba(26, 115, 232, 0.1)'
                      }}
                   />
                   {isCurrent && activeStage !== 'OVERVIEW' && (
                      <motion.path 
                          layoutId="hub-outline"
                          d={SVG_PATHS[hub.unifiedPath]} 
                          className={styles.hubOutline}
                          initial={{ pathLength: 0 }}
                          animate={{ pathLength: 1 }}
                          transition={{ duration: 1 }}
                      />
                   )}
                </g>
              );
            })}

            {/* Q Logo Inline SVG (Zero-Box Solution) */}
            <motion.g 
                animate={{ 
                    x: activeHub.logoPos.x, 
                    y: activeHub.logoPos.y,
                    scale: activeStage === 'OVERVIEW' ? 0.10 : activeHub.logoScale || 0.18
                }}
                transition={{ type: 'spring', stiffness: 50, damping: 15 }}
                className={styles.qMarkerWrapper}
            >
              <g transform="translate(-322.5, -193.5)"> {/* Center the 645x387 logo */}
                <path d="M 253.22 195.75 C253.01,247.16 252.67,261.99 251.72,261.97 C249.72,261.91 199.77,210.23 196.32,204.65 C194.58,201.82 192.21,196.13 191.07,192.02 C189.07,184.80 189.00,182.23 189.00,119.27 L 189.00 54.00 L 251.25 54.01 C288.04,54.01 316.16,54.43 320.00,55.02 C323.80,55.61 329.62,57.58 334.00,59.76 C340.86,63.17 343.81,65.82 368.66,90.99 C383.59,106.12 395.61,118.82 395.36,119.22 C395.12,119.62 365.43,119.96 329.38,119.99 C326.53,119.99 323.79,119.99 321.16,119.99 C268.36,120.02 261.25,120.02 257.83,123.57 C257.13,124.30 256.58,125.18 255.83,126.23 L 253.50 129.50 Z" fill="#0672c4"/>
                <path d="M 414.90 302.25 L 443.37 331.00 L 387.93 330.93 C327.28,330.86 327.40,330.87 315.61,324.85 C310.58,322.27 304.70,316.85 282.31,294.14 C267.35,278.96 255.30,266.37 255.52,266.14 C255.75,265.92 283.73,265.81 317.71,265.90 L 379.50 266.07 L 382.97 269.78 C384.88,271.83 399.25,286.44 414.90,302.25 Z" fill="#39a259"/>
                <path d="M 461.79 244.00 C461.96,270.67 461.96,296.67 461.80,301.78 L 461.50 311.05 L 396.93 246.36 L 397.04 183.68 C397.09,149.21 397.45,121.01 397.82,121.01 C398.95,121.04 451.32,175.02 453.96,178.89 C455.31,180.88 457.56,185.43 458.95,189.00 L 461.48 195.50 Z" fill="#7a57ba"/>
              </g>
            </motion.g>
          </motion.svg>
        </div>

        {/* HUD Info Box */}
        <div className={styles.infoOverlay}>
          <AnimatePresence mode="wait">
            {activeStage === 'REGION_ACTIVE' && activeHub && (
              <motion.div 
                key={activeHub.id}
                className={styles.infoCard}
                initial={{ opacity: 0, scale: 0.9, x: isRTL ? -100 : 100 }}
                animate={{ opacity: 1, scale: 1, x: 0 }}
                exit={{ opacity: 0, scale: 0.9, x: isRTL ? 100 : -100 }}
                transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
              >
                <div className={styles.cardHeader}>
                  <div className={styles.headerIndicator} />
                  <span className={styles.preText}>{t('footprint_label')}</span>
                </div>
                <h2 className={styles.regionTitle}>
                  {language === 'en' ? activeHub.nameEn : activeHub.nameAr}
                </h2>
                <div className={styles.statGrid}>
                  {activeHub.stats.map((stat, idx) => (
                    <div key={idx} className={styles.statItem}>
                      <span className={styles.statLabel}>
                        {language === 'en' ? stat.labelEn : stat.labelAr}
                      </span>
                      <span className={styles.statValue}>
                        <AnimatedCounter value={stat.value} suffix={stat.suffix} />
                      </span>
                    </div>
                  ))}
                </div>
                <div className={styles.cardFooter}>
                  <div className={styles.footerLine} />
                  <span className={styles.statusText}>IMMERSIVE_MODE_LINK_{activeHub.id.toUpperCase()}</span>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </section>
  );
}
